// Merge part 3 into main MoleculesDB
function mergeMegaMolecules3() {
    for (const [key, value] of Object.entries(MoleculesDBMega3)) {
        if (!MoleculesDB[key]) {
            MoleculesDB[key] = value;
        }
    }
}

if (typeof MoleculesDB !== 'undefined') mergeMegaMolecules3();
